import{_ as e,a}from"./chunks/添加渠道.o1VHzHEI.js";import{_ as d,o,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Hugging Face チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/huggingface.md","filePath":"ja-JP/upload/huggingface.md","lastUpdated":1781962217000}'),n={name:"ja-JP/upload/huggingface.md"};function l(g,t,c,s,h,p){return o(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="hugging-face-チャンネルの追加" tabindex="-1">Hugging Face チャンネルの追加 <a class="header-anchor" href="#hugging-face-チャンネルの追加" aria-label="Permalink to &quot;Hugging Face チャンネルの追加&quot;">​</a></h1><p>Hugging Face チャンネルは、Hugging Face の Repository をファイル保存先として利用します。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Hugging Face アカウント</td><td>Repository と Token を管理します</td></tr><tr><td>Repository</td><td>ファイルの保存先</td></tr><tr><td>Access Token</td><td>ImgBed から Repository へ書き込むため</td></tr><tr><td>保存ディレクトリ</td><td>任意。ファイルを置くパス</td></tr></tbody></table><h2 id="token-を作成する" tabindex="-1">Token を作成する <a class="header-anchor" href="#token-を作成する" aria-label="Permalink to &quot;Token を作成する&quot;">​</a></h2><p>Hugging Face の設定画面で Access Token を作成します。Repository へ書き込める権限を付与してください。</p><p><img src="'+e+'" alt="Token 作成" loading="lazy"></p><p>Token は作成後にコピーし、安全に保存します。</p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>Hugging Face</code> を選びます。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>HF Storage</code></td></tr><tr><td>Repository</td><td><code>ユーザー名/リポジトリ名</code></td></tr><tr><td>Token</td><td>Hugging Face Access Token</td></tr><tr><td>保存ディレクトリ</td><td>任意。通常は <code>imgbed</code></td></tr><tr><td>備考</td><td>任意</td></tr></tbody></table><p><img src="'+a+'" alt="チャンネル追加" loading="lazy"></p><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><ol><li>保存後にチャンネルカードが表示される。</li><li>テスト画像をアップロードする。</li><li>Hugging Face Repository にファイルが追加される。</li><li>ImgBed のリンクからアクセスできる。</li></ol><h2 id="運用の注意" tabindex="-1">運用の注意 <a class="header-anchor" href="#運用の注意" aria-label="Permalink to &quot;運用の注意&quot;">​</a></h2><ul><li>Repository の公開範囲に注意してください。公開 Repository に置いたファイルは外部から見える可能性があります。</li><li>Token には必要な権限だけを付けます。</li><li>大量ファイルの保存や高頻度配信では、Hugging Face 側の制限に注意してください。</li></ul>',16)])])}const b=d(n,[["render",l]]);export{_ as __pageData,b as default};
